head.script:
scwin.statusFlag = "";
scwin.processFlag = "";
scwin.v_contractno = "";
scwin.tabIndex = 0;
scwin.v_linkcheck = "";
scwin.v_kcomcd = "";
scwin.v_blno = "";
scwin.v_mhno = "";
scwin.v_bkno = "";
scwin.hd_kcomcd = "DBEX";
scwin.hd_bkbltype = "B";
scwin.ed_groupNo = "";
scwin.hd_bkIo = "O";
scwin.ed_wgt = "";
scwin.vCurDate = "";
scwin.strPreDate = "";
scwin.currentTime = "";
scwin.userId = "";

scwin.onpageload = function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.strPreDate = $c.date.addDate(scwin.vCurDate, -2);
    scwin.userId = $c.ses.getUserId();

    let now = new Date();
    let hof = now.getHours().toString();
    let mm = now.getMinutes().toString();
    if (hof.length == 1) hof = "0" + hof;
    if (mm.length == 1) mm = "0" + mm;
    scwin.currentTime = hof + mm;

    let params = $c.data.getParameter();
    if (params != null) {
        scwin.v_linkcheck = params.linkcheck || "0";
        scwin.v_kcomcd = params.kcomcd || "";
        scwin.v_blno = params.blno || "";
        scwin.v_mhno = params.mhno || "";
        scwin.v_bkno = params.bkno || "";
    }

    scwin.f_DefaultValue();
    scwin.f_Check();
    scwin.f_getParametrSetting(scwin.v_linkcheck);
};

scwin.onUdcCompleted = function() {
};

scwin.f_getParametrSetting = function(gubun) {
    switch (gubun) {
        case "0":
            break;
        case "1":
            let vk = scwin.v_kcomcd;
            let vb = scwin.v_bkno;
            if (vb == "null" || vb == "") {
                lc_cfs.setValue("");
                lc_cfs.setFocus();
                return false;
            }
            scwin.hd_kcomcd = vk;
            lc_cfs.setValue(vb);
            scwin.f_Retrieve();
            break;
    }
};

scwin.f_Check = function() {
    lc_cfs.setSelectedIndex(0);
};

scwin.f_DefaultValue = function() {
    scwin.f_initSetTab();
    scwin.f_Set("INIT");
    lc_cfs.setFocus();
    scwin.processFlag = "T";
};

scwin.f_initSetTab = function() {
    $c.gus.cfEnableObjects([btn_Find]);
    $c.gus.cfViewTab(0);
};

scwin.f_Set = function(gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_Copy, btn_Cancel, btn_Save, btn_Delete, btn_Update, btn_Print, btn_HouseBl, btn_HouseBl2,
                btn_OrderSendDel, btn_OrderSend, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Find]);
            scwin.f_DisablePopUpObj();
            $c.gus.cfEnableObjects([lc_cfs]);
            scwin.statusFlag = "I";
            break;
        case "RETRIEVE":
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel,
                btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2]);
            $c.gus.cfEnableBtnOnly([btn_Copy, btn_Create, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_Find, btn_HouseBl, btn_HouseBl2]);
            gr_containerDoorOrder.setColumnVisible("chk", true);
            gr_containerDoorOrder.setColumnReadOnly("chk", false);
            gr_containerDoorOrder.setColumnReadOnly("doordt", true);
            gr_containerDoorOrder.setColumnReadOnly("bkdoorseq", true);
            gr_containerDoorOrder.setColumnReadOnly("internalTyp", true);
            gr_containerDoorOrder.setColumnReadOnly("transcd", true);
            gr_containerDoorOrder.setColumnReadOnly("transnm", true);
            gr_containerDoorOrder.setColumnReadOnly("fcity", true);
            gr_containerDoorOrder.setColumnReadOnly("fcitynm", true);
            gr_containerDoorOrder.setColumnReadOnly("fdt", true);
            gr_containerDoorOrder.setColumnReadOnly("doorcd", true);
            gr_containerDoorOrder.setColumnReadOnly("doornm", true);
            gr_containerDoorOrder.setColumnReadOnly("tcity", true);
            gr_containerDoorOrder.setColumnReadOnly("tcitynm", true);
            gr_containerDoorOrder.setColumnReadOnly("closingdt", true);
            gr_containerDoorOrder.setColumnReadOnly("remark", true);
            gr_containerDoorOrderQty.setReadOnly("grid", true);
            if (scwin.statusFlag == "C") {
                $c.gus.cfDisableBtnOnly([btn_Update]);
            } else {
                $c.gus.cfEnableBtnOnly([btn_Update]);
            }
            $c.gus.cfEnableObjects([lc_cfs]);
            scwin.statusFlag = "";
            break;
        case "CREATE":
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Copy, btn_Create, btn_Update, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_HouseBl, btn_HouseBl2]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, btn_Find,
                btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2]);
            gr_containerDoorOrder.setColumnVisible("chk", false);
            gr_containerDoorOrder.setColumnReadOnly("doordt", false);
            gr_containerDoorOrder.setColumnReadOnly("bkdoorseq", true);
            gr_containerDoorOrder.setColumnReadOnly("internalTyp", false);
            gr_containerDoorOrder.setColumnReadOnly("transcd", false);
            gr_containerDoorOrder.setColumnReadOnly("transnm", true);
            gr_containerDoorOrder.setColumnReadOnly("fcity", false);
            gr_containerDoorOrder.setColumnReadOnly("fcitynm", true);
            gr_containerDoorOrder.setColumnReadOnly("fdt", false);
            gr_containerDoorOrder.setColumnReadOnly("doorcd", false);
            gr_containerDoorOrder.setColumnReadOnly("doornm", true);
            gr_containerDoorOrder.setColumnReadOnly("tcity", false);
            gr_containerDoorOrder.setColumnReadOnly("tcitynm", true);
            gr_containerDoorOrder.setColumnReadOnly("closingdt", false);
            gr_containerDoorOrder.setColumnReadOnly("remark", false);
            gr_containerDoorOrderQty.setReadOnly("grid", false);
            $c.gus.cfDisableObjects([lc_cfs]);
            scwin.statusFlag = "C";
            break;
        case "UPDATE":
            $c.gus.cfDisableBtnOnly([btn_Copy, btn_Update, btn_Create, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_HouseBl, btn_HouseBl2]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, btn_Find,
                btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2]);
            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();
            gr_containerDoorOrder.setColumnVisible("chk", false);
            gr_containerDoorOrder.setColumnReadOnly("doordt", false);
            gr_containerDoorOrder.setColumnReadOnly("bkdoorseq", true);
            gr_containerDoorOrder.setColumnReadOnly("internalTyp", false);
            gr_containerDoorOrder.setColumnReadOnly("transcd", false);
            gr_containerDoorOrder.setColumnReadOnly("transnm", true);
            gr_containerDoorOrder.setColumnReadOnly("fcity", false);
            gr_containerDoorOrder.setColumnReadOnly("fcitynm", true);
            gr_containerDoorOrder.setColumnReadOnly("fdt", false);
            gr_containerDoorOrder.setColumnReadOnly("doorcd", false);
            gr_containerDoorOrder.setColumnReadOnly("doornm", true);
            gr_containerDoorOrder.setColumnReadOnly("tcity", false);
            gr_containerDoorOrder.setColumnReadOnly("tcitynm", true);
            gr_containerDoorOrder.setColumnReadOnly("closingdt", false);
            gr_containerDoorOrder.setColumnReadOnly("remark", false);
            gr_containerDoorOrderQty.setReadOnly("grid", false);
            $c.gus.cfDisableObjects([lc_cfs]);
            scwin.statusFlag = "U";
            break;
        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Delete, btn_Cancel, btn_Print]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create]);
            scwin.f_Set("RETRIEVE");
            break;
    }
};

scwin.f_EnablePopUpObj = function() {
    $c.gus.cfEnableObjects([udc_reDt, udc_bkEtd, udc_bkEta]);
    $c.gus.cfEnableObjects([udc_doc, udc_docSeq, udc_cust, udc_custSeq, udc_fac, udc_facAttn,
        udc_liner, udc_linerattn, udc_vsl, udc_sales, udc_lod, udc_dis, udc_dlv, udc_dept, udc_item, udc_bkArea, udc_unit]);
};

scwin.f_DisablePopUpObj = function() {
    $c.gus.cfDisableObjects([udc_reDt, udc_bkEtd, udc_bkEta]);
    $c.gus.cfDisableObjects([udc_doc, udc_docSeq, udc_cust, udc_custSeq, udc_fac, udc_facAttn,
        udc_liner, udc_linerattn, udc_vsl, udc_sales, udc_lod, udc_dis, udc_dlv, udc_dept, udc_item, udc_bkArea, udc_unit]);
};

scwin.f_selectTabMenu = function(idx) {
    switch (idx) {
        case 0:
            scwin.tabIndex = 0;
            break;
        case 1:
            scwin.tabIndex = 1;
            if (ds_containerDoorOrder.getRowCount() == 0) {
                scwin.f_autoCreateDoorOrderInfo();
            }
            break;
    }
    $c.gus.cfViewTab(idx);
};

scwin.f_RetrieveBinding = function(dma, gubun) {
    switch (gubun) {
        case "RetrieveBooking":
            dma.set("kcomcd", scwin.hd_kcomcd);
            dma.set("bkNo", lc_cfs.getValue());
            dma.set("inpid", scwin.userId);
            break;
        case "RetrieveBookingNo":
            dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
            dma_retrieve.set("bkEtd", ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "bkEtd"));
            dma_retrieve.set("inpid", scwin.userId);
            break;
        case "RetrieveBookingHbl":
            dma.set("kcomcd", scwin.hd_kcomcd);
            dma.set("bkNo", ed_bkNo.getValue());
            dma.set("seq", ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq"));
            dma.set("inpid", scwin.userId);
            break;
        case "SaveContainerBooking":
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds_containerDoorOrder.setCellData(ds_containerDoorOrder.getRowPosition(), "groupNo", scwin.ed_groupNo);
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "bkbltype", scwin.hd_bkbltype);
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "bkEtd", udc_bkEtd.getValue());
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "inpid", scwin.userId);
            break;
        case "SaveContainerDoorOrder":
            ds_containerDoorOrder.setCellData(ds_containerDoorOrder.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds_containerDoorOrder.setCellData(ds_containerDoorOrder.getRowPosition(), "inpid", scwin.userId);
            break;
        case "SaveContainerDoorOrderQty":
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "inpid", scwin.userId);
            break;
        case "SaveBookingContainer":
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "inpid", scwin.userId);
            break;
        case "DeleteContainerDoorOrder":
            ds_containerDoorOrder.setCellData(ds_containerDoorOrder.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds_containerDoorOrder.setCellData(ds_containerDoorOrder.getRowPosition(), "inpid", scwin.userId);
            break;
        case "DeleteContainerDoorOrderQty":
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "inpid", scwin.userId);
            break;
        case "DeleteBookingContainer":
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "inpid", scwin.userId);
            break;
        case "UpdateContainerDoorOrder":
            ds_containerDoorOrder.setCellData(ds_containerDoorOrder.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds_containerDoorOrder.setCellData(ds_containerDoorOrder.getRowPosition(), "inpid", scwin.userId);
            break;
        case "UpdateContainerDoorOrderQty":
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "inpid", scwin.userId);
            break;
        case "UpdateBookingContainer":
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "inpid", scwin.userId);
            break;
    }
};

scwin.f_Retrieve = async function() {
    if (lc_cfs.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, ["Booking No"]);
        return;
    } else {
        dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
        dma_retrieve.set("bkNo", lc_cfs.getValue());
        dma_retrieve.set("bkbltype", scwin.hd_bkbltype);
        ed_mtwgt.setValue("");
        await $c.sbm.execute(sbm_retrieve);
        lc_cfs.setFocus();
    }
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(lc_cfs);
};

scwin.f_Create = function() {
    scwin.f_Set("CREATE");
    lc_cfs.setValue("");
    ds_containerBookingList.insertRow();
    ds_containerDoorOrder.removeAll();
    ds_containerDoorOrderQty.removeAll();
    ds_houseblList.removeAll();
    ed_mtwgt.setValue("");
    scwin.f_Check();
    $c.gus.cfViewTab(0);
    ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "reDt", scwin.vCurDate);
    udc_reDt.setFocus();
};

scwin.f_Update = async function() {
    // TODO: ds_bkCloseCheck 동적 URL 조회 — 원본은 DataID+Reset 패턴
    let param1 = scwin.hd_kcomcd;
    let param2 = lc_cfs.getValue();
    sbm_bkCloseCheck.action = "/cm.zz.RetrieveComboCMD.do?sysCd=SeaExportBookingEBC&queryId=retrivebkCloseCheck&param1=" + param1 + "&param2=" + param2;
    await $c.sbm.execute(sbm_bkCloseCheck);
    if (ds_bkCloseCheck.getRowCount() > 0 && ds_bkCloseCheck.getCellData(0, "CODE") == "Y") {
        await $c.win.alert("Bring to a close");
        return;
    }

    if (ed_bkNo.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["HEADER"]);
        return;
    } else {
        $c.gus.cfDisableObjects([btn_Clear]);
        scwin.f_Set("UPDATE");
    }
};

scwin.f_Save = async function() {
    if (ds_containerBookingList.isUpdated() || ds_containerDoorOrder.isUpdated() || ds_containerDoorOrderQty.isUpdated()) {
        if (await scwin.f_validate()) {
            let chk = await $c.win.confirm(E_MSG_CM_CRM_001);
            if (chk) {
                if (ed_bkNo.getValue() == "") {
                    dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
                    dma_retrieve.set("bkEtd", ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "bkEtd"));
                    await $c.sbm.execute(sbm_retrievebookingNo);
                    ed_bkNo.setValue(ds_retrieveNo.getCellData(0, "bkNo"));
                }

                dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
                dma_retrieve.set("bkNo", ed_bkNo.getValue());
                dma_retrieve.set("seq", ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq"));
                await $c.sbm.execute(sbm_retrievebookingHbl);

                if (ds_bookingHbl.getCellData(ds_bookingHbl.getRowPosition(), "hblno") == "" || ds_bookingHbl.getRowCount() == 0) {
                    ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
                    ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "bkbltype", scwin.hd_bkbltype);
                    ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "bkEtd", udc_bkEtd.getValue());
                    ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "inpid", scwin.userId);

                    if (ds_containerDoorOrder.getRowCount() == 0) {
                        scwin.f_autoCreateDoorOrderInfo();
                    } else {
                        ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "bkNo", ed_bkNo.getValue());
                        ds_containerDoorOrder.setCellData(ds_containerDoorOrder.getRowPosition(), "bkNo", ed_bkNo.getValue());
                    }

                    await $c.sbm.execute(sbm_save);
                } else {
                    await $c.gus.cfAlertMsg(E_MSG_CM_WRN_011, ["House B/L"]);
                }
                scwin.f_Set("SAVE");
                lc_cfs.setValue(ed_bkNo.getValue());
                scwin.f_Retrieve();
            }
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["Container Booking"]);
    }
};

scwin.f_Cancel = function() {
    if (scwin.statusFlag == "C") {
        scwin.f_Set("INIT");
    } else {
        scwin.f_Set("RETRIEVE");
        ds_containerBookingList.undoAll();
        ds_ctrtNo.undoAll();
        scwin.f_cancelRow(1);
        scwin.f_cancelRow(2);
        lc_cfs.setFocus();
        scwin.processFlag = "T";
    }
};

scwin.f_autoCreateDoorOrderInfo = function() {
    ds_containerDoorOrder.insertRow();
    ds_containerDoorOrderQty.insertRow();

    let rowDoor = ds_containerDoorOrder.getRowPosition();
    ds_containerDoorOrder.setCellData(rowDoor, "kcomcd", scwin.hd_kcomcd);
    ds_containerDoorOrder.setCellData(rowDoor, "bkNo", ed_bkNo.getValue());
    ds_containerDoorOrder.setCellData(rowDoor, "doordt", "200911061532");
    ds_containerDoorOrder.setCellData(rowDoor, "bkdoorseq", "01");
    ds_containerDoorOrder.setCellData(rowDoor, "internalTyp", "2");
    ds_containerDoorOrder.setCellData(rowDoor, "transcd", "109856");
    ds_containerDoorOrder.setCellData(rowDoor, "inpid", "seokjy");

    let rowQty = ds_containerDoorOrderQty.getRowPosition();
    ds_containerDoorOrderQty.setCellData(rowQty, "kcomcd", scwin.hd_kcomcd);
    ds_containerDoorOrderQty.setCellData(rowQty, "bkNo", ed_bkNo.getValue());
    ds_containerDoorOrderQty.setCellData(rowQty, "bkdoorseq", "01");
    ds_containerDoorOrderQty.setCellData(rowQty, "qtytype", "M/T");
    scwin.f_doorTypeQtyLoading(rowQty, "qtytype");
    ds_containerDoorOrderQty.setCellData(rowQty, "inpid", "seokjy");
};

scwin.f_Copy = function() {
    scwin.f_Set("CREATE");
    lc_cfs.setValue("");
    ds_containerDoorOrder.removeAll();
    ds_containerDoorOrderQty.removeAll();
    ds_houseblList.removeAll();
    ds_ctrtNo.removeAll();
    scwin.f_Check();

    if (ds_containerBookingList.getRowCount() != 0) {
        ds_containerBookingList.setRowStatus(ds_containerBookingList.getRowPosition(), "C");
    }
    ed_bkNo.setValue("");
    ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "custCd", "");
    ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "custNm", "");
    ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "salesCd", "");
    ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "salesNm", "");

    $c.gus.cfViewTab(0);
    udc_reDt.setFocus();
};

scwin.f_Delete = async function() {
    let param1 = scwin.hd_kcomcd;
    let param2 = lc_cfs.getValue();
    sbm_bkCloseCheck.action = "/cm.zz.RetrieveComboCMD.do?sysCd=SeaExportBookingEBC&queryId=retrivebkCloseCheck&param1=" + param1 + "&param2=" + param2;
    await $c.sbm.execute(sbm_bkCloseCheck);
    if (ds_bkCloseCheck.getRowCount() > 0 && ds_bkCloseCheck.getCellData(0, "CODE") == "Y") {
        await $c.win.alert("Bring to a close");
        return;
    }

    let errorChk = 0;
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "sendDt") != "") {
            await $c.win.alert("Order sended : Order No -> " + ds_containerDoorOrder.getCellData(i, "bkNo") + ",Seq -> " + ds_containerDoorOrder.getCellData(i, "bkdoorseq"));
            errorChk = 1;
        }
    }
    if (errorChk == 1) return;

    scwin.f_RetrieveBinding(dma_retrieve, "RetrieveBookingHbl");
    await $c.sbm.execute(sbm_retrievebookingHbl);
    if (ds_bookingHbl.getCellData(ds_bookingHbl.getRowPosition(), "hblno") != "undefined" && ds_bookingHbl.getRowCount() != 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["House B/L", "delete"]);
        return;
    }

    let chk = await $c.win.confirm(E_MSG_CM_CRM_004);
    if (chk) {
        ds_containerBookingList.removeAll();

        scwin.f_RetrieveBinding(dma_retrieve, "RetrieveBookingHbl");
        await $c.sbm.execute(sbm_retrievebookingHbl);

        await $c.sbm.execute(sbm_delete);

        lc_cfs.setValue("");
        ds_containerBookingList.removeAll();
        ds_containerDoorOrder.removeAll();
        ds_containerDoorOrderQty.removeAll();
        ds_houseblList.removeAll();

        scwin.f_Set("INIT");
        lc_cfs.setValue("");
    }
};

scwin.f_orderSend = async function() {
    if (ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "internalTyp") == "1") {
        if (ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "itemCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Item"]);
            $c.gus.cfViewTab(0);
            ed_itemCd.setFocus();
            return;
        }

        let errorChk = 0;
        let j = 0;
        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                j = j + 1;
            }
        }
        if (j == 0) errorChk = 1;

        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                let v_orderno = ds_containerDoorOrder.getCellData(i, "bkNo");
                let v_seq = ds_containerDoorOrder.getCellData(i, "bkdoorseq");
                let vk = scwin.hd_kcomcd;
                sbm_doorOrderQtyCheck.action = "/cm.zz.RetrieveComboCMD.do?sysCd=SeaExportBookingEBC&queryId=retrivedoorOrderQtyCheck&param1=" + vk + "&param2=" + v_orderno + "&param3=" + v_seq;
                await $c.sbm.execute(sbm_doorOrderQtyCheck);
                if (ds_doorOrderQtyCheck.getRowCount() > 0 && ds_doorOrderQtyCheck.getCellData(0, "CODE") == "0") {
                    errorChk = 1;
                    await $c.win.alert("Door Order Qty is not exist: Order No -> " + v_orderno + ",Seq -> " + v_seq);
                }
            }
        }
        if (errorChk == 0) {
            for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
                if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                    ds_containerDoorOrder.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                    if (ds_containerDoorOrder.getCellData(i, "sendDt") == "") {
                        ds_containerDoorOrder.setCellData(i, "orderType", 1);
                    } else {
                        ds_containerDoorOrder.setCellData(i, "orderType", 2);
                    }
                    ds_containerDoorOrder.setCellData(i, "inpid", scwin.userId);
                }
            }
            await $c.sbm.execute(sbm_saveOrderSend);
            scwin.f_Retrieve();
        }
    } else {
        await $c.win.alert("Normal Type");
        return;
    }
};

scwin.f_orderSendDel = async function() {
    if (ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "internalTyp") == "1") {
        let errorChk = 0;

        let j = 0;
        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                j = j + 1;
            }
        }
        if (j == 0) errorChk = 1;

        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                if (ds_containerDoorOrder.getCellData(i, "sendDt") == "") {
                    await $c.win.alert("Order is not sended : Order No -> " + ds_containerDoorOrder.getCellData(i, "bkNo") + ",Seq -> " + ds_containerDoorOrder.getCellData(i, "bkdoorseq"));
                    errorChk = 1;
                }
            }
        }

        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                if (ds_containerDoorOrder.getCellData(i, "mcomOdrNo") != "") {
                    await $c.win.alert("Order sended : Order No -> " + ds_containerDoorOrder.getCellData(i, "bkNo") + ",Seq -> " + ds_containerDoorOrder.getCellData(i, "bkdoorseq"));
                    errorChk = 1;
                }
            }
        }
        if (errorChk == 0) {
            for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
                if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                    ds_containerDoorOrder.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                    ds_containerDoorOrder.setCellData(i, "orderType", 3);
                    ds_containerDoorOrder.setCellData(i, "inpid", scwin.userId);
                }
            }
            await $c.sbm.execute(sbm_saveOrderSend);
            scwin.f_Retrieve();
        }
    } else {
        await $c.win.alert("Normal Type");
        return;
    }
};

scwin.f_addRow = async function(disGubun) {
    switch (disGubun) {
        case 1:
            if (ed_bkNo.getValue() == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking Header"]);
            } else {
                ds_containerDoorOrder.insertRow();
                let rowPos = ds_containerDoorOrder.getRowPosition();
                let v_seq = (rowPos + 1).toString();
                let v_seqResult = $c.str.lpad(v_seq, "0", 2);
                ds_containerDoorOrder.setCellData(rowPos, "bkdoorseq", v_seqResult);
                ds_containerDoorOrder.setCellData(rowPos, "kcomcd", scwin.hd_kcomcd);
                ds_containerDoorOrder.setCellData(rowPos, "bkNo", ed_bkNo.getValue());
                ds_containerDoorOrder.setCellData(rowPos, "internalTyp", "1");
                ds_containerDoorOrder.setCellData(rowPos, "inpid", scwin.userId);
                ds_containerDoorOrder.setCellData(rowPos, "doordt", scwin.vCurDate + scwin.currentTime);
                gr_containerDoorOrder.setFocusedCell(rowPos, "doordt");
            }
            break;
        case 2:
            if (ed_bkNo.getValue() == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking Header"]);
            } else {
                if (ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq") == "" || ds_containerDoorOrder.getRowCount() == 0) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Booking Door Order"]);
                } else {
                    ds_containerDoorOrderQty.insertRow();
                    let rowPos = ds_containerDoorOrderQty.getRowPosition();
                    ds_containerDoorOrderQty.setCellData(rowPos, "kcomcd", scwin.hd_kcomcd);
                    ds_containerDoorOrderQty.setCellData(rowPos, "bkNo", ed_bkNo.getValue());
                    ds_containerDoorOrderQty.setCellData(rowPos, "bkdoorseq", ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq"));
                    ds_containerDoorOrderQty.setCellData(rowPos, "inpid", scwin.userId);
                    gr_containerDoorOrderQty.setFocusedCell(rowPos, "qtytype");
                }
            }
            break;
    }
};

scwin.f_deleteRow = async function(disGubun) {
    switch (disGubun) {
        case 1:
            if (ds_containerDoorOrderQty.getRowCount() > 0) {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Door Order Quantity Or Container", "delete"]);
            } else if (ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "sendDt") != "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Order sended", "delete"]);
            } else {
                ds_containerDoorOrder.removeRow(ds_containerDoorOrder.getRowPosition());
            }
            break;
        case 2:
            ds_containerDoorOrderQty.removeRow(ds_containerDoorOrderQty.getRowPosition());
            break;
    }
};

scwin.f_cancelRow = function(disGubun) {
    switch (disGubun) {
        case 1:
            ds_containerDoorOrder.undoAll();
            ds_containerDoorOrderQty.undoAll();
            break;
        case 2:
            ds_containerDoorOrderQty.undoAll();
            break;
    }
};

scwin.f_validate = async function() {
    if (scwin.tabIndex == 0) {
        if (!(await scwin.f_BookingTabValidate())) {
            return false;
        }
    } else if (scwin.tabIndex == 1) {
        if (!(await scwin.f_DoorOrderTabValidate())) {
            return false;
        }
    }
    return true;
};

scwin.f_BookingTabValidate = async function() {
    let chk = await $c.gus.cfValidate([udc_reDt, udc_bkEtd, udc_bkEta]);
    if (!chk) {
        return false;
    }

    if (udc_bkEtd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETD"]);
        udc_bkEtd.setFocus();
        return false;
    }

    if (udc_bkEta.getValue() != "") {
        if (!$c.gus.cfIsAfterDate(udc_bkEtd.getValue(), udc_bkEta.getValue())) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["ETD", "ETA"]);
            udc_bkEtd.setFocus();
            return false;
        }
    }

    if (ed_custCd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]);
        ed_custCd.setFocus();
        return false;
    }

    if (ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "ctrtNo") == "선택" || lc_contractno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Contract No"]);
        ed_custCd.setFocus();
        return false;
    }

    if (ed_dept.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Department"]);
        ed_dept.setFocus();
        return false;
    }

    return true;
};

scwin.f_DoorOrderTabValidate = async function() {
    let msg = "[Booking] ";
    let chk = await $c.gus.cfValidate([gr_containerDoorOrder]);
    if (!chk) {
        return false;
    }

    if (udc_bkEtd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "ETD"]);
        return false;
    }

    if (udc_bkEta.getValue() != "") {
        if (!$c.gus.cfIsAfterDate(udc_bkEtd.getValue(), udc_bkEta.getValue())) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["ETD", "ETA"]);
            udc_bkEtd.setFocus();
            return false;
        }
    }

    if (ed_custCd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "Customer"]);
        return false;
    }

    if (ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "ctrtNo") == "선택" || lc_contractno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "Contract No"]);
        return false;
    }

    if (ed_dept.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "Department"]);
        return false;
    }

    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getRowStatus(i) != "D") {
            if (ds_containerDoorOrder.getRowCount() > 0) {
                if (ds_containerDoorOrderQty.getRowCount() == 0) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Door Order Qty"]);
                    return false;
                }
            }
        }
    }

    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "bkdoorseq") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Door Order Seq"]);
            gr_containerDoorOrder.setFocusedCell(i, "bkdoorseq");
            return false;
        }
    }

    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "doordt") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Container Order Date"]);
            gr_containerDoorOrder.setFocusedCell(i, "doordt");
            return false;
        }
    }

    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "transcd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Container Order Trucker"]);
            gr_containerDoorOrder.setFocusedCell(i, "transcd");
            return false;
        }
    }

    for (let i = 0; i < ds_containerDoorOrderQty.getRowCount(); i++) {
        if (ds_containerDoorOrderQty.getCellData(i, "qtytype") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Door Order Container Type"]);
            gr_containerDoorOrderQty.setFocusedCell(i, "qtytype");
            return false;
        }
    }

    return true;
};

