        let cfrm = await $c.win.confirm("Freight Charge Code List를 EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            $c.data.downloadGridViewExcel(gr_houseblList, {fileName: "Freight Charge Code List.xlsx", sheetName: "Freight Charge Code List"});
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
