    sbm_doorGridType.action = "/cm.zz.RetrieveComboCMD.do?sysCd=SeaExportBookingEBC&queryId=retriveTypeList&param1=" + cnt1 + "&param2=" + cnt2 + "&param3=" + cnt3 + "&param4=" + cnt4;
