scwin.f_doorTypeQtyLoading = function(row, colid) {
    let wgt = Number(ed_mtwgt.getValue()) / 1000;
    let msr = Number(ed_msr.getValue());
    let qtytype = ds_containerDoorOrderQty.getCellData(ds_containerDoorOrderQty.getRowPosition(), "qtytype");
    if (qtytype == "WGT" || qtytype == "M/T") {
        ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "qty", ed_mtwgt.getValue());
    } else if (qtytype == "R/T") {
        if (wgt > msr) {
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "qty", wgt);
        } else {
            ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "qty", msr);
        }
    } else if (qtytype == "CBM") {
        ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition(), "qty", msr);
    }
};

