            ds_containerDoorOrder.getCellData(Row, "transnm"),
            pWinCloseTF, '10',
            'Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN',
            '140,300,100,100,100,100,100,,,100', '8,9', null, null, null, null, null, null,
            pAllSearchTF, 'Customer search,Customer Code,Customer Name', 'F');
            break;
        case "Department":
            udc_dept.ilCommonPopUp(function(rtnList) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_containerDoorOrder, Row, "transcd", "transnm");
            },
            ds_containerDoorOrder.getCellData(Row, "transcd"),
            ds_containerDoorOrder.getCellData(Row, "transnm"),
            pWinCloseTF, '2', "Code, Name", '80,230', "3,4,5,6,7,8,9,10",
            null, null, null, null, null, null, pAllSearchTF, "Department,Code,Name", 'F');
            break;
        case "PickupCy":
            udc_lod.ilCommonPopUp(function(rtnList) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_containerDoorOrder, Row, "fcity", "fcitynm");
            },
            ds_containerDoorOrder.getCellData(Row, "fcity"),
            ds_containerDoorOrder.getCellData(Row, "fcitynm"),
            pWinCloseTF, '2', "Code, Name", '80,230', "3,4,5,6,7,8,9,10",
            null, null, null, null, null, null, pAllSearchTF, "CY,Code,Name", 'F');
            break;
        case "Door":
            udc_dlv.ilCommonPopUp(function(rtnList) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_containerDoorOrder, Row, "doorcd", "doornm");
            },
            ds_containerDoorOrder.getCellData(Row, "doorcd"),
            ds_containerDoorOrder.getCellData(Row, "doornm"),
            pWinCloseTF, '2', "Code, Name", '80,230', "3,4,5,6,7,8,9,10",
            null, null, null, null, null, null, pAllSearchTF, 'Door search,Door Code,Door Name', 'F');
            break;
        case "GateinCy":
            udc_dis.ilCommonPopUp(function(rtnList) {
