scwin.gr_containerDoorOrder_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    switch (columnId) {
        case "transcd":
            if (ds_containerDoorOrder.getCellData(rowIndex, "internalTyp") == "1") {
                scwin.f_PopUpGrid("Department", rowIndex, "F");
            } else {
                scwin.f_PopUpGrid("Customer", rowIndex, "F");
            }
            break;
        case "fcity":
            scwin.f_PopUpGrid("PickupCy", rowIndex, "F");
            break;
        case "doorcd":
            scwin.f_PopUpGrid("Door", rowIndex, "F");
            break;
        case "tcity":
            scwin.f_PopUpGrid("GateinCy", rowIndex, "F");
            break;
        case "doordt":
            $c.gus.cfOpenCalendar(gr_containerDoorOrder, rowIndex, columnId);
            break;
        case "fdt":
            $c.gus.cfOpenCalendar(gr_containerDoorOrder, rowIndex, columnId);
            break;
        case "closingdt":
            $c.gus.cfOpenCalendar(gr_containerDoorOrder, rowIndex, columnId);
            break;
        case "sendDt":
            $c.gus.cfOpenCalendar(gr_containerDoorOrder, rowIndex, columnId);
            break;
    }
};

scwin.gr_containerDoorOrder_oneditend = async function(rowIndex, columnIndex, columnId, oldValue, newValue) {
    if (rowIndex >= 0 && ds_containerDoorOrder.getRowCount() > rowIndex) {
        switch (columnId) {
            case "transcd":
                if (ds_containerDoorOrder.getCellData(rowIndex, columnId).trim() != "") {
                    if (ds_containerDoorOrder.getCellData(rowIndex, "internalTyp") == "1") {
                        ds_containerDoorOrder.setCellData(rowIndex, "transnm", "");
                        scwin.f_PopUpGrid("Department", rowIndex, "T");
                    } else {
                        ds_containerDoorOrder.setCellData(rowIndex, "transnm", "");
                        scwin.f_PopUpGrid("Customer", rowIndex, "T");
                    }
                } else {
                    ds_containerDoorOrder.setCellData(rowIndex, "transcd", "");
                    ds_containerDoorOrder.setCellData(rowIndex, "transnm", "");
                }
                break;
            case "fcity":
                if (ds_containerDoorOrder.getCellData(rowIndex, columnId).trim() != "") {
                    ds_containerDoorOrder.setCellData(rowIndex, "fcitynm", "");
                    scwin.f_PopUpGrid("PickupCy", rowIndex, "T");
                } else {
                    ds_containerDoorOrder.setCellData(rowIndex, "fcity", "");
                    ds_containerDoorOrder.setCellData(rowIndex, "fcitynm", "");
                }
                break;
            case "doorcd":
                if (ds_containerDoorOrder.getCellData(rowIndex, columnId).trim() != "") {
                    ds_containerDoorOrder.setCellData(rowIndex, "doornm", "");
                    scwin.f_PopUpGrid("Door", rowIndex, "T");
                } else {
                    ds_containerDoorOrder.setCellData(rowIndex, "doorcd", "");
                    ds_containerDoorOrder.setCellData(rowIndex, "doornm", "");
                }
                break;
            case "tcity":
                if (ds_containerDoorOrder.getCellData(rowIndex, columnId).trim() != "") {
                    ds_containerDoorOrder.setCellData(rowIndex, "tcitynm", "");
                    scwin.f_PopUpGrid("GateinCy", rowIndex, "T");
                } else {
                    ds_containerDoorOrder.setCellData(rowIndex, "tcity", "");
                    ds_containerDoorOrder.setCellData(rowIndex, "tcitynm", "");
                }
                break;
            case "bkdoorseq":
                for (let i = 0; i < ds_containerDoorOrder.getRowCount() - 1; i++) {
                    for (let j = i + 1; j < ds_containerDoorOrder.getRowCount(); j++) {
                        if (ds_containerDoorOrder.getCellData(i, "bkdoorseq") == ds_containerDoorOrder.getCellData(j, "bkdoorseq")) {
                            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, ["Container Seq"]);
                            gr_containerDoorOrder.setFocusedCell(rowIndex, "bkdoorseq");
                            return;
                        }
                    }
                }
                break;
        }
    }
};

scwin.gr_containerDoorOrderQty_oneditend = async function(rowIndex, columnIndex, columnId, oldValue, newValue) {
    if (columnId == "qtytype") {
        for (let i = 0; i < ds_containerDoorOrderQty.getRowCount() - 1; i++) {
            for (let j = i + 1; j < ds_containerDoorOrderQty.getRowCount(); j++) {
                if (ds_containerDoorOrderQty.getCellData(i, "qtytype") == ds_containerDoorOrderQty.getCellData(j, "qtytype")) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, ["Container Type"]);
                    gr_containerDoorOrderQty.setFocusedCell(rowIndex, "qtytype");
                    return;
                }
            }
        }
        scwin.f_doorTypeQtyLoading(rowIndex, columnId);
    }
};

